CREATE TABLE rate_types ( id serial, name character varying (127) NOT NULL, description text DEFAULT NULL, CONSTRAINT pk_rate_types PRIMARY KEY (id) ); CREATE INDEX i_rate_types_name ON rate_types (name);
INSERT INTO rate_types (id, name, description) VALUES (1, 'Salary', 'Pay monthly based salary') , (2, 'Hourly', 'Hourly rate for contractors') , (3, 'Daily', 'Daily rate for contractors') , (4, 'Weekly', 'Weekly rate for contractors') , (5, 'Monthly', 'Monthly rate for contractors') , (6, 'Annually', 'Annual rate for contractors') ;
ALTER SEQUENCE rate_types_id_seq RESTART WITH 7;
